    let ir = std::fs::read_to_string(virtualized_ir).expect("virtualized memory intrinsic IR should be readable");
    assert!(ir.contains(".amice.vm.bytecode.vm_memory_intrinsics"));
    assert!(ir.contains("handler.load"));
