#[test]
#[serial]
fn test_vm_virtualize_call_native_writes_final_return_slot_without_copy() {
    ensure_plugin_built();

    let source = output_dir().join("vm_virtualize_call_native_direct_ret_slot.c");
    std::fs::write(
        &source,
        r#"#include <stdio.h>
__attribute__((noinline))
int native_value(void) {
    volatile int value = 41;
    return value + 1;
}
__attribute__((noinline, annotate("+vm_virtualize")))
int vm_native_ret_slot(void) {
    return native_value();
}
int main(void) {
    printf("%d\n", vm_native_ret_slot());
    return 0;
}
"#,
    )
    .expect("native return-slot fixture should be writable");

    let baseline = CppCompileBuilder::new(&source, "vm_virtualize_call_native_direct_ret_slot_baseline")
        .optimization("O1")
        .without_plugin()
        .compile();
    baseline.assert_success();
    let baseline_output = baseline.run();
    baseline_output.assert_success();
    assert_eq!("42\n", baseline_output.stdout());

    let mut config = ObfuscationConfig::disabled();
    config.vm_emit_markers = Some(true);
    config.vm_dump_bytecode = Some(true);
    let virtualized =
        compile_virtualized_binary_with_config(&source, "vm_virtualize_call_native_direct_ret_slot", config.clone());
    virtualized.assert_success();
    let virtualized_output = virtualized.run();
    virtualized_output.assert_success();
    assert_eq!(baseline_output.stdout(), virtualized_output.stdout());

    let (ir_path, output) =
        compile_virtualized_ir_with_debug_log(&source, "vm_virtualize_call_native_direct_ret_slot.ll", config);
    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
    assert_success(output);
    let dump = bytecode_dump_for_function(&stderr, "vm_native_ret_slot");
    assert!(dump.contains(": call_native "));
    assert!(dump.contains(": ret "));
    assert!(
        !dump.contains(": mov "),
        "call_native should write the final return slot directly, dump was:\n{dump}"
    );

    let ir = std::fs::read_to_string(ir_path).expect("native return-slot output IR should be readable");
    assert!(ir.contains(".amice.vm.bytecode.vm_native_ret_slot"));
    assert!(ir.contains("handler.call_native"));
}

#[test]
#[serial]
fn test_vm_virtualize_sret_abi_matches_baseline() {
    ensure_plugin_built();

    let ir_source = output_dir().join("vm_virtualize_sret_abi.input.ll");
    std::fs::write(
        &ir_source,
        r#"; ModuleID = 'vm_virtualize_sret_abi'
source_filename = "vm_virtualize_sret_abi.ll"

%Big = type { i64, i64, i64 }

declare void @native_sret(ptr sret(%Big) align 8, i64)

define void @vm_sret_direct(ptr noalias sret(%Big) align 8 %out, i64 %x) #0 {
entry:
  %a = add i64 %x, 11
  %b = mul i64 %x, 3
  %c = xor i64 %a, %b
  %pa = getelementptr inbounds %Big, ptr %out, i32 0, i32 0
  %pb = getelementptr inbounds %Big, ptr %out, i32 0, i32 1
  %pc = getelementptr inbounds %Big, ptr %out, i32 0, i32 2
  store i64 %a, ptr %pa, align 8
  store i64 %b, ptr %pb, align 8
  store i64 %c, ptr %pc, align 8
  ret void
}

define i64 @vm_sret_native(i64 %x) #0 {
entry:
  %tmp = alloca %Big, align 8
  call void @native_sret(ptr sret(%Big) align 8 %tmp, i64 %x)
  %pa = getelementptr inbounds %Big, ptr %tmp, i32 0, i32 0
  %pb = getelementptr inbounds %Big, ptr %tmp, i32 0, i32 1
  %pc = getelementptr inbounds %Big, ptr %tmp, i32 0, i32 2
  %a = load i64, ptr %pa, align 8
  %b = load i64, ptr %pb, align 8
  %c = load i64, ptr %pc, align 8
  %m0 = add i64 %a, %b
  %m1 = xor i64 %m0, %c
  ret i64 %m1
}

attributes #0 = { noinline optnone }
"#,
    )
    .expect("sret ABI LLVM IR fixture should be writable");

    let harness = output_dir().join("vm_virtualize_sret_abi_harness.c");
    std::fs::write(
        &harness,
        r#"#include <stdint.h>
#include <stdio.h>

struct Big {
    int64_t a;
    int64_t b;
    int64_t c;
};

struct Big vm_sret_direct(int64_t x);
int64_t vm_sret_native(int64_t x);

struct Big native_sret(int64_t x) {
    struct Big out;
    out.a = x + 7;
    out.b = x * 5;
    out.c = out.a ^ out.b;
    return out;
}

static int64_t mix_direct(int64_t x) {
    struct Big got = vm_sret_direct(x);
    return (got.a + got.b) ^ got.c;
}

int main(void) {
    int64_t acc = 0;
    acc ^= mix_direct(37);
    acc ^= mix_direct(-91);
    acc ^= vm_sret_native(123);
    acc ^= vm_sret_native(-456);
    printf("%lld\n", (long long)acc);
    return 0;
}
"#,
    )
    .expect("sret ABI C harness should be writable");

    let baseline = compile_ir_with_c_harness(&ir_source, &harness, "vm_virtualize_sret_abi_baseline");
    baseline.assert_success();
    let baseline_output = baseline.run();
    baseline_output.assert_success();

    let mut config = vm_virtualize_config();
    config.vm_dump_bytecode = Some(true);
    let (virtualized_ir, output) = optimize_ir_with_plugin_debug(&ir_source, "vm_virtualize_sret_abi.ll", config);
    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
    assert_success(output);
    let direct_dump = bytecode_dump_for_function(&stderr, "vm_sret_direct");
    assert!(
        direct_dump.contains(": store ") && direct_dump.contains(": ret "),
        "direct sret body should lower stores to the ABI return pointer and terminate in VM:\n{direct_dump}"
    );
    let native_dump = bytecode_dump_for_function(&stderr, "vm_sret_native");
    assert!(
        native_dump.contains(": call_native ") && native_dump.contains(": load "),
        "native sret call should lower through call_native and reload the returned aggregate fields:\n{native_dump}"
    );

    let virtualized = compile_ir_with_c_harness(&virtualized_ir, &harness, "vm_virtualize_sret_abi");
    virtualized.assert_success();
    let virtualized_output = virtualized.run();
    virtualized_output.assert_success();
    assert_eq!(baseline_output.stdout(), virtualized_output.stdout());

    let ir = std::fs::read_to_string(virtualized_ir).expect("virtualized sret ABI IR should be readable");
    assert!(ir.contains(".amice.vm.bytecode.vm_sret_direct"));
    assert!(ir.contains(".amice.vm.bytecode.vm_sret_native"));
    assert!(
        ir.lines()
            .find(|line| line.starts_with("define ") && line.contains("@vm_sret_direct("))
            .is_some_and(|line| line.contains("sret(%Big)")),
        "direct sret wrapper must preserve the typed sret ABI attribute"
    );
    assert!(ir.contains(".amice.vm.native_thunk.vm_sret_native"));
    assert!(
        ir.lines()
            .any(|line| line.contains("call void @native_sret(") && line.contains("sret(%Big)")),
        "native sret thunk call must preserve the callee sret ABI attribute"
    );
}

#[test]
#[serial]
fn test_vm_virtualize_direct_varargs_native_call_matches_baseline() {
    ensure_plugin_built();

    let ir_source = output_dir().join("vm_virtualize_varargs_native.input.ll");
    std::fs::write(
        &ir_source,
        r#"; ModuleID = 'vm_virtualize_varargs_native'
source_filename = "vm_virtualize_varargs_native.ll"

@fmt = private unnamed_addr constant [13 x i8] c"%d:%lld:%.1f\00"

declare i32 @snprintf(ptr, i64, ptr, ...)

define i64 @vm_varargs_native(ptr %buf, i32 %x, i64 %salt, double %scale) #0 {
entry:
  %written = call i32 (ptr, i64, ptr, ...) @snprintf(ptr %buf, i64 96, ptr @fmt, i32 %x, i64 %salt, double %scale)
  %w64 = sext i32 %written to i64
  %p0 = getelementptr i8, ptr %buf, i64 0
  %b0 = load i8, ptr %p0, align 1
  %p1 = getelementptr i8, ptr %buf, i64 1
  %b1 = load i8, ptr %p1, align 1
  %p2 = getelementptr i8, ptr %buf, i64 2
  %b2 = load i8, ptr %p2, align 1
  %p3 = getelementptr i8, ptr %buf, i64 3
  %b3 = load i8, ptr %p3, align 1
  %p4 = getelementptr i8, ptr %buf, i64 4
  %b4 = load i8, ptr %p4, align 1
  %p5 = getelementptr i8, ptr %buf, i64 5
  %b5 = load i8, ptr %p5, align 1
  %p6 = getelementptr i8, ptr %buf, i64 6
  %b6 = load i8, ptr %p6, align 1
  %p7 = getelementptr i8, ptr %buf, i64 7
  %b7 = load i8, ptr %p7, align 1
  %z0 = zext i8 %b0 to i64
  %z1 = zext i8 %b1 to i64
  %z2 = zext i8 %b2 to i64
  %z3 = zext i8 %b3 to i64
  %z4 = zext i8 %b4 to i64
  %z5 = zext i8 %b5 to i64
  %z6 = zext i8 %b6 to i64
  %z7 = zext i8 %b7 to i64
  %r0 = add i64 %w64, %z0
  %r1 = shl i64 %z1, 8
  %r2 = xor i64 %r0, %r1
  %r3 = shl i64 %z2, 16
  %r4 = xor i64 %r2, %r3
  %r5 = shl i64 %z3, 24
  %r6 = add i64 %r4, %r5
  %r7 = shl i64 %z4, 32
  %r8 = xor i64 %r6, %r7
  %r9 = shl i64 %z5, 40
  %r10 = add i64 %r8, %r9
  %r11 = shl i64 %z6, 48
  %r12 = xor i64 %r10, %r11
  %r13 = shl i64 %z7, 56
  %r14 = add i64 %r12, %r13
  %ret = xor i64 %r14, %salt
  ret i64 %ret
}

attributes #0 = { noinline optnone }
"#,
    )
    .expect("varargs native LLVM IR fixture should be writable");

    let harness = output_dir().join("vm_virtualize_varargs_native_harness.c");
    std::fs::write(
        &harness,
        r#"#include <stdint.h>
#include <stdio.h>

uint64_t vm_varargs_native(char *buf, int32_t x, uint64_t salt, double scale);

int main(void) {
    char first[96];
    char second[96];
    uint64_t a = vm_varargs_native(first, 37, 123456ULL, 4.5);
    uint64_t b = vm_varargs_native(second, -8, 987654321ULL, -2.25);
    printf("%llu:%s\n%llu:%s\n", (unsigned long long)a, first, (unsigned long long)b, second);
    return 0;
}
"#,
    )
    .expect("varargs native C harness should be writable");

    let baseline = compile_ir_with_c_harness(&ir_source, &harness, "vm_virtualize_varargs_native_baseline");
    baseline.assert_success();
    let baseline_output = baseline.run();
    baseline_output.assert_success();

    let mut config = vm_virtualize_config();
    config.vm_dump_bytecode = Some(true);
    let (virtualized_ir, output) = optimize_ir_with_plugin_debug(&ir_source, "vm_virtualize_varargs_native.ll", config);
    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
    assert_success(output);
    let dump = bytecode_dump_for_function(&stderr, "vm_varargs_native");
    assert!(
        dump.contains(": call_native "),
        "direct varargs native call should lower through call_native:\n{dump}"
    );

    let virtualized = compile_ir_with_c_harness(&virtualized_ir, &harness, "vm_virtualize_varargs_native");
    virtualized.assert_success();
    let virtualized_output = virtualized.run();
    virtualized_output.assert_success();
    assert_eq!(baseline_output.stdout(), virtualized_output.stdout());

    let ir = std::fs::read_to_string(virtualized_ir).expect("virtualized varargs native IR should be readable");
    assert!(ir.contains(".amice.vm.bytecode.vm_varargs_native"));
    assert!(ir.contains(".amice.vm.native_thunk.vm_varargs_native"));
    assert!(ir.contains("handler.call_native"));
}

